# Secure cache key generation
def generate_cache_key(prefix, *args):
    key_string = f"{prefix}:{':'.join(str(arg) for arg in args)}"
    return hashlib.sha256(key_string.encode()).hexdigest()

# Secure cache decorator
def secure_cache(ttl=300):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            # Generate cache key from function name and arguments
            cache_key = generate_cache_key(f.__name__, *args, **kwargs)
            
            # Try to get from cache
            cached_result = client.get(cache_key)
            if cached_result is not None:
                return json.loads(cached_result)
            
            # Execute function and cache result
            result = f(*args, **kwargs)
            
            # Cache the result
            client.set(cache_key, json.dumps(result), time=ttl)
            return result
        return decorated_function
    return decorator

